  import sailpoint.object.SailpointContext;
  import sailpoint.object.Custom;
  import sailpoint.object.Identity;
  import sailpoint.object.EmailOptions;
  import sailpoint.object.EmailTemplate;
  import sailpoint.object.Attributes;
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.ProvisioningPlan.Operation;  
  import sailpoint.object.ProvisioningPlan.AccountRequest; 
  import sailpoint.object.ProvisioningPlan.AttributeRequest;
  import sailpoint.object.WorkflowLaunch;
  import sailpoint.tools.Util;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;	
  import sailpoint.object.ProvisioningPlan.AccountRequest.Operation;
  import sailpoint.object.ProvisioningResult;
  import sailpoint.object.Application;

  //import sailpoint.connector.ConnectorClassLoader;

  //ClassLoader currentCl = Thread.currentThread().getContextClassLoader();
  //ClassLoader bakcedUpCl = null;
  //if(currentCl instanceof ConnectorClassLoader){
    //bakcedUpCl = currentCl;
    //Thread.currentThread().setContextClassLoader(currentCl.getParent());
  //}

  /**
		 * 
		 * @Send Email if operation is create Account for users    
		 */

  Log logger = LogFactory.getLog("rule.afterProvisioning.Voalte");

  logger.debug("Entering Voalte After Provisioning Rule");

  String toEmail = null;
  Identity owner = null;
  List roleNames = new ArrayList();
  HashMap distributionLists = new HashMap();
  LinkedHashMap argValues = new LinkedHashMap();
  List status = new ArrayList();
  boolean sendEmail = false;

  if (plan != null ) { 	

    List accountRequests = plan.getAccountRequests(application.getName());
    if(null != accountRequests && !accountRequests.isEmpty()){
      for(AccountRequest accountRequest : accountRequests){


        if(accountRequest != null && accountRequest.getResult() != null){ 

          if(null != accountRequest.getAttributeRequest("client_type_access")){
            if(accountRequest.getAttributeRequest("client_type_access").getValue() instanceof String &&  Util.nullSafeCaseInsensitiveEq(accountRequest.getAttributeRequest("client_type_access").getValue(),"voalte_one")){
              sendEmail = true;
            }else if(accountRequest.getAttributeRequest("client_type_access").getValue() instanceof List &&  accountRequest.getAttributeRequest("client_type_access").getValue().contains("voalte_one")){
              sendEmail = true;
            }
          }


          if(sendEmail && Util.isNotNullOrEmpty(accountRequest.getResult().getStatus()) && accountRequest.getResult().getStatus().equalsIgnoreCase("COMMITTED") ){

            List attrReqs = accountRequest.getAttributeRequests("role");

            for(AttributeRequest attrReq : attrReqs){
              if(null != attrReq){
                status.add(attrReq.getResult());
                roleNames.add(attrReq.getValue());
              }
            }

            if(null != accountRequest.getOperation() && (AccountRequest.Operation.Create.equals(accountRequest.getOperation()) || AccountRequest.Operation.Modify.equals(accountRequest.getOperation()) )&& null != plan.getIdentity()){
              owner = plan.getIdentity().getManager();

              toEmail = "ahnat-mb-voalteteam@ascension.org";

              argValues.put("User's Name",plan.getIdentity().getDisplayName());   
              argValues.put("User's Network ID Provided By User (May be blank)",plan.getIdentity().getAttribute("samAccountName"));
              argValues.put("User's Email Address",plan.getIdentity().getAttribute("email"));
              argValues.put("User's Type",plan.getIdentity().getAttribute("type"));
              argValues.put("Job Title",plan.getIdentity().getAttribute("title"));  
              argValues.put("Department",plan.getIdentity().getAttribute("department"));               
              argValues.put("Location",plan.getIdentity().getAttribute("location"));
              argValues.put("Employee Number",plan.getIdentity().getAttribute("employeeId"));
              argValues.put("Telephone Number",plan.getIdentity().getAttribute("mobile"));

              if(null != owner){
                argValues.put("Manager's Name",owner.getDisplayName());
                argValues.put("Manager's Phone Number",owner.getAttribute("mobile"));
                argValues.put("Manager's Department",owner.getAttribute("department"));
                argValues.put("Manager's Email Address",owner.getAttribute("email"));

              }
              if(!Util.isEmpty(plan.getRequesters()) && null != plan.getRequesters().get(0)){

                argValues.put("Submitter's Name",plan.getRequesters().get(0).getDisplayName());
                argValues.put("Submitter's Phone Number",plan.getRequesters().get(0).getAttribute("mobile"));
                argValues.put("Submitter's Email Address",plan.getRequesters().get(0).getAttribute("email"));
              }

              argValues.put("Application Name",application.getName());
              argValues.put("Action","Add");
              argValues.put("Hospital or Site","");
              argValues.put("Role",plan.getIdentity().getAttribute("employeeId"));
              argValues.put("ENTITLEMENTS",roleNames);
              argValues.put("Provisioning Comments For Application",plan.getComments());
              argValues.put("Application Username Provided by Provisioning","");
              argValues.put("Requestor Comments For Application",plan.getComments());
              argValues.put("General Request Comments",plan.getComments());

            }

            EmailTemplate template = context.getObjectByName(EmailTemplate.class, "Ascension-EmailTemplate-Voalte-ManagerNotification");
            EmailOptions options = new EmailOptions();
            if(Util.isNotNullOrEmpty(toEmail)){
              options.setTo(toEmail);
            }    

            Map args = new HashMap();
            args.put("map",argValues);
            args.put("identityDisplayName",plan.getIdentity().getDisplayName());
            args.put("subject","Action Needed for voalte_one");

            options.setVariables(args);
            if(Util.isNotNullOrEmpty(toEmail) && template !=null){
              context.sendEmailNotification(template,options);             
            }
          }        
        }
      }          
    }
  }
